# --- TLS Configuration ---

def load_tls_credentials() -> Optional[grpc.ServerCredentials]:
    """Load TLS certificates for secure communication."""
    cert_path = os.environ.get('GRPC_TLS_CERT', '')
    key_path = os.environ.get('GRPC_TLS_KEY', '')
    ca_path = os.environ.get('GRPC_TLS_CA', '')

    if not cert_path or not key_path:
        logger.warning("TLS certificates not configured. Running WITHOUT TLS is insecure!")
        return None

    try:
        with open(key_path, 'rb') as f:
            private_key = f.read()
        with open(cert_path, 'rb') as f:
            certificate_chain = f.read()

        root_certificates = None
        require_client_auth = False
        if ca_path and os.path.exists(ca_path):
            with open(ca_path, 'rb') as f:
                root_certificates = f.read()
            require_client_auth = True
            logger.info("Mutual TLS (mTLS) enabled")

        credentials = grpc.ssl_server_credentials(
            [(private_key, certificate_chain)],
            root_certificates=root_certificates,
            require_client_auth=require_client_auth,
        )
        logger.info("TLS credentials loaded successfully")
        return credentials

    except FileNotFoundError as e:
        logger.error(f"TLS certificate file not found: {e}")
        raise
    except Exception as e:
        logger.error(f"Failed to load TLS credentials: {e}")
        raise


