def serve():
    """Main entry point to start the server."""
    bind_address = os.environ.get('GRPC_BIND_ADDRESS', '0.0.0.0')
    port = int(os.environ.get('GRPC_PORT', '50051'))
    max_workers = int(os.environ.get('GRPC_MAX_WORKERS', '10'))

    # Load auth tokens from environment (comma-separated)
    auth_tokens_str = os.environ.get('GRPC_AUTH_TOKENS', '')
    auth_tokens = set(filter(None, auth_tokens_str.split(','))) if auth_tokens_str else None

    server, metrics = create_server(
        bind_address=bind_address,
        port=port,
        max_workers=max_workers,
        auth_tokens=auth_tokens,
    )

    shutdown_event = Event()

    def graceful_shutdown(signum, frame):
        logger.info(f"Received signal {signum}. Initiating graceful shutdown...")
        shutdown_event.set()
        # Grace period for in-flight requests
        grace_period = 30
        stopped_event = server.stop(grace_period)
        stopped_event.wait()
        logger.info("Server stopped gracefully")
        logger.info(f"Final metrics: {metrics.snapshot()}")

    signal.signal(signal.SIGTERM, graceful_shutdown)
    signal.signal(signal.SIGINT, graceful_shutdown)

    server.start()
    logger.info(f"gRPC server started on {bind_address}:{port} with {max_workers} workers")
    if auth_tokens:
        logger.info(f"Authentication enabled with {len(auth_tokens)} token(s)")
    else:
        logger.warning("Authentication is DISABLED. Set GRPC_AUTH_TOKENS to enable.")

    # Periodic metrics logging
    try:
        while not shutdown_event.is_set():
            shutdown_event.wait(timeout=60)
            if not shutdown_event.is_set():
                logger.info(f"Server metrics: {metrics.snapshot()}")
    except KeyboardInterrupt:
        graceful_shutdown(signal.SIGINT, None)


